  ambessa: { diff: "HARD", tone: "#ff5d6c", tldr: "She dives with dashes \u2014 condemn her, play safe.", breakdown: "Ambessa chains dashes onto you. Condemn her engage, play safe, and scale.", dos: ["Condemn her dash engage", "Play safe vs her dive", "Scale to out-DPS her"], donts: ["Trade into her full combo", "Get caught by her dashes", "Get caught flat-footed"], key: { slot: "E", name: "Repeating Dashes", cd: "12s", note: "Her mobility. Condemn the follow-up.", winT: "DASHES DOWN", winS: "W-shred + kite her." }, hold: "Hold E to condemn her when she dash-chains in \u2014 break her combo.", tip: "Her dash-chain mobility sticks to you \u2014 condemn her engage and play safe until you out-scale.", win: "Condemn her dive and scale safely." },
