  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — kite him apart with tumble + true damage.","breakdown":"Akshan plays around Heroic Swing. Space him with Q tumbles, stack W bolts for the %max-HP true damage, and Condemn his Heroic Swing engage into a wall. Doran’s Shield blunts the poke war.","dos":["Kite with Q tumble","Proc 3 silver bolts per trade","Condemn-stun him when Heroic Swing is down"],"donts":["Tumble into his Heroic Swing","Fight in melee range","Waste Condemn with no wall"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Condemn + silver-bolt shred."},"win":"Kite him apart with tumble + true damage."},
  cassiopeia: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — kite him apart with tumble + true damage.","breakdown":"Cassiopeia plays around Miasma. Space him with Q tumbles, stack W bolts for the %max-HP true damage, and Condemn his Miasma engage into a wall. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Kite with Q tumble","Proc 3 silver bolts per trade","Condemn-stun him when Miasma is down"],"donts":["Tumble into his Miasma","Fight in melee range","Waste Condemn with no wall"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Condemn + silver-bolt shred."},"win":"Kite him apart with tumble + true damage."},
