  graves: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — kite him apart with tumble + true damage.","breakdown":"Graves plays around Quickdraw. Space him with Q tumbles, stack W bolts for the %max-HP true damage, and Condemn his Quickdraw engage into a wall.","dos":["Kite with Q tumble","Proc 3 silver bolts per trade","Condemn-stun him when Quickdraw is down"],"donts":["Tumble into his Quickdraw","Fight in melee range","Waste Condemn with no wall"],"key":{"slot":"E","name":"Quickdraw","cd":"13s","note":"His dash + armor stacks. Engage when it's down.","winT":"QUICKDRAW DOWN","winS":"Condemn + silver-bolt shred."},"win":"Kite him apart with tumble + true damage."},
